class TweetCounts {
public:
    unordered_map<string, unordered_map<int, int>> tweetMap;
    TweetCounts() {

    }

    void recordTweet(string tweetName, int time) {
        tweetMap[tweetName][time]++;
    }

    vector<int> getTweetCountsPerFrequency(string freq, string tweetName, int startTime, int endTime) {
        vector<int> res;
        int chunkSize;
        if (freq == "minute") {
            chunkSize = 60;
        } else if (freq == "hour") {
            chunkSize = 3600;
        } else {
            chunkSize = 86400;
        }
        int left = startTime, right = startTime;
        while (left <= endTime) {
            int count = 0;
            while (right <= endTime && right < left + chunkSize) {
                count += tweetMap[tweetName].count(right) ? tweetMap[tweetName][right] : 0;
                right++;
            }
            res.push_back(count);
            left += chunkSize;
        }
        return res;
    }
};

```
